var colors=new Array([62,35,255],[60,255,60],[255,35,98],[45,175,230],[255,0,255],[255,128,0]);var step=0;var colorIndices=[0,1,2,3];var gradientSpeed=.002;function updateGradient(){if($===undefined)return;var r=colors[colorIndices[0]];var o=colors[colorIndices[1]];var e=colors[colorIndices[2]];var t=colors[colorIndices[3]];var a=1-step;var n=Math.round(a*r[0]+step*o[0]);var c=Math.round(a*r[1]+step*o[1]);var s=Math.round(a*r[2]+step*o[2]);var d="rgb("+n+","+c+","+s+")";var l=Math.round(a*e[0]+step*t[0]);var i=Math.round(a*e[1]+step*t[1]);var v=Math.round(a*e[2]+step*t[2]);var p="rgb("+l+","+i+","+v+")";$(".gradient").css({background:"-webkit-gradient(linear, left top, right top, from("+d+"), to("+p+"))"}).css({background:"-moz-linear-gradient(left, "+d+" 0%, "+p+" 100%)"});step+=gradientSpeed;if(step>=1){step%=1;colorIndices[0]=colorIndices[1];colorIndices[2]=colorIndices[3];colorIndices[1]=(colorIndices[1]+Math.floor(1+Math.random()*(colors.length-1)))%colors.length;colorIndices[3]=(colorIndices[3]+Math.floor(1+Math.random()*(colors.length-1)))%colors.length}}setInterval(updateGradient,10);